import psycopg2

def search_users(username=None, email=None, role=None, status=None):
    # Connect to the PostgreSQL database
    conn = psycopg2.connect(
        host="localhost",
        dbname="mydatabase",
        user="myuser",
        password="mypassword"
    )
    
    # Create a cursor object
    cur = conn.cursor()
    
    # Define the query based on the input parameters
    if username and email:
        query = "SELECT * FROM users WHERE username=%s AND email=%s"
        params = (username, email)
    elif role and status:
        query = "SELECT * FROM users WHERE role=%s AND status=%s"
        params = (role, status)
    else:
        query = "SELECT * FROM users"
        params = ()
    
    # Execute the query
    cur.execute(query, params)
    
    # Fetch the results
    rows = cur.fetchall()
    
    # Close the cursor and the connection
    cur.close()
    conn.close()
    
    return rows